+  | "agent_task"
+  | "conditional"
+  | "parallel"
+  | "approval"
+  | "script"
+  | "loop"
+  | "wait"
+  | "transform"
+  | "webhook"
+  | "sub_pipeline";
+
+export type TriggerType = "manual" | "schedule" | "webhook" | "bead_event";
+
