+  id: string;
+  name: string;
+  description?: string;
+  type: StepType;
+  status: StepStatus;
+  startedAt?: string;
+  completedAt?: string;
+  result?: {
+    success: boolean;
+    output?: unknown;
+    error?: { code: string; message: string };
+    durationMs: number;
+  };
+}
+
+export interface PipelineTrigger {
+  type: TriggerType;
+  enabled: boolean;
+  lastTriggeredAt?: string;
+  nextTriggerAt?: string;
+}
